static char *xdg_user_dir_lookup (const char *type)
{
    const char *home_dir;
    char *dir, *user_dir;

    dir = xdg_user_dir_lookup_with_fallback(type, NULL);
    if (dir)
        return dir;

    home_dir = SDL_getenv("HOME");

    if (!home_dir)
        return NULL;

    // Special case desktop for historical compatibility
    if (SDL_strcmp(type, "DESKTOP") == 0) {
        size_t length = SDL_strlen(home_dir) + SDL_strlen("/Desktop") + 1;
        user_dir = (char *)SDL_malloc(length);
        if (!user_dir)
            return NULL;

        SDL_strlcpy(user_dir, home_dir, length);
        SDL_strlcat(user_dir, "/Desktop", length);
        return user_dir;
    }

    return NULL;
}

static int scancode_to_SDL(int scancode)
{
    int button = 0;
    switch (scancode) {
    // D-Pad buttons on the left JoyCon
    case BTN_DPAD_UP:
        button = SDL_GAMEPAD_BUTTON_DPAD_UP;
        break;
    case BTN_DPAD_DOWN:
        button = SDL_GAMEPAD_BUTTON_DPAD_DOWN;
        break;
    case BTN_DPAD_LEFT:
        button = SDL_GAMEPAD_BUTTON_DPAD_LEFT;
        break;
    case BTN_DPAD_RIGHT:
        button = SDL_GAMEPAD_BUTTON_DPAD_RIGHT;
        break;

    default:
        return -1;
    }
    SDL_assert(button < ANDROID_MAX_NBUTTONS);
    return button;
}

bool SDL_SYS_SetThreadPriority(SDL_ThreadPriority priority)
{
    int value = VITA_THREAD_PRIORITY_NORMAL;

    switch (priority) {
    case SDL_THREAD_PRIORITY_LOW:
        value = VITA_THREAD_PRIORITY_LOW;
        break;
    case SDL_THREAD_PRIORITY_NORMAL:
        value = VITA_THREAD_PRIORITY_NORMAL;
        break;
    case SDL_THREAD_PRIORITY_HIGH:
        value = VITA_THREAD_PRIORITY_HIGH;
        break;
    case SDL_THREAD_PRIORITY_TIME_CRITICAL:
        value = VITA_THREAD_PRIORITY_TIME_CRITICAL;
        break;
    }

    if (sceKernelChangeThreadPriority(0, value) < 0) {
        return SDL_SetError("sceKernelChangeThreadPriority() failed");
    }
    return true;
}

static void DOSVESA_SetWindowSize(SDL_VideoDevice *device, SDL_Window *window)
{
    SDL_VideoDisplay *display = SDL_GetVideoDisplayForWindow(window);
    if (!display) {
        return;
    }

    SDL_DisplayMode closest;
    SDL_DisplayMode *mode = NULL;
    if (SDL_GetClosestFullscreenDisplayMode(display->id, window->floating.w, window->floating.h, 0.0f, false, &closest)) {
        mode = &closest;
    }

    DOSVESA_ApplyModeForWindow(display, window, mode);

    // Invalidate the framebuffer so it gets recreated at the new size.
    window->surface_valid = false;
}
